$(document).ready(function(){$("#branch_id").select2({placeholder:"Select One",allowClear:!0}),$(".form").on("submit",function(a){$("#amount").val()==""&&(notify("You Need To Select Valid Branch Which has Balance","warning"),a.preventDefault()),$("#amount").val()<1&&(notify("Amount is = 0, Add Amount","warning"),a.preventDefault())}),$("#branch_id").change(function(){var a=parseFloat($("#branch_id").find(":selected").data("amount")),t=parseFloat($("#branch_id").find(":selected").data("w_amount")),n=parseFloat(a)-parseFloat(t);$("#amount_show").removeClass("d-none"),$("#amount_show").html("Branch Available Balance is: "+n),a>0,$("#amount").attr("max",n)})});
